31:41',NULL,NULL,'active','active',0,NULL,NULL,NULL,NULL,3,'3工作日',0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,7,1,NULL),('25999ad4-b70b-428c-accf-ee2aa50a37bc','zcrm_6302359000000489166','zcrm_6302359000000469001','Leion','zcrm_6302359000000469001','Leion','zcrm_6302359000000469001','Leion','2024-04-15 05:11:00','2024-05-30 06:30:00','2024-06-27 07:58:42',NULL,NULL,'印尼投资活动报告申报 (LKPM )/季度','LPKM',NULL,NULL,NULL,NULL,NULL,1,'TaxService','/次',1,NULL,NULL,NULL,0,'1. OSS ID 和密码\n2. 工资表明细／员工信息　（几个印尼员工，几个外籍员工；分析几个男员工，几个女员工）\n3. 公司章程＋SK，包括更新版\n4. 全部 NIB\n5. 法人和股东的资料　（护照,KITAS/KITAB,税卡，身份证）\n6. 财务报表　（损益表，资产负债表，日记账，现金流量表, 财务报告附注)','1. 企业投资活动报告（LKPM）是投资部 BKPM 要求所有在印尼境内的外资公司在每季度对公司的现况报告。申报 LKPM 时，需要注意财务报表的信息，尤其是资本的部分。2. LKPM 需要在每个季度申报。3. 每个投资企业都必须申报企业投资活动报告 LKPM 并将其提交给投资部。对于未按报告期提交 LKPM 的企业，投资部将向企业发出警告信，最差情况可能会受到取消营业执照的处罚。',NULL,'6c0cf973-9af3-4b7c-a25d-02c0f0dc9b8e','2024-04-15 05:11:00','2025-11-18 09:31:41',NULL,NULL,'active','active',0,NULL,NULL,NULL,NULL,5,'5工作日',0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,7,1,NULL),('25a26c7e-6392-41c6-bb52-3c37a0451e31','zcrm_6302359000000489171','zcrm_6302359000000469001','Leion','zcrm_6302359000000469001','Leion','zcrm_6302359000000469001','Leion','2024-04-15 05:11:00','2024-05-30 06:30:00','2024-09-18 19:05:17',NULL,NULL,'进口许可证API-U','API_U',NULL,NULL,NULL,NULL,NULL,1,'LicenseService','/次',1,NULL,NULL,NULL,0,NULL,NULL,NULL,'177a4cd6-7084-49e2-91aa-ca7a979e7ec8','2024-04-15 05:11:00','2025-11-18 09:31:41',NULL,NULL,'active','active',0,NULL,NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,7,1,NULL),('282842d2-2cf0-4819-aa70-faa65ea1271b','zcrm_6302359000000489181','zcrm_6302359000000469001','Leion','zcrm_6302359000000469001','Leion','zcrm_6302359000000469001','Leion','2024-05-30 06:30:00','2024-05-30 06:30:00','2024-06-30 18:19:57',NULL,NULL,'护照换新,原签证迁移','VisaToNewPassport',N